var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"做好心理準備後呼喚她，收到回覆說在約定的地點等待中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"반려끼리 평생을 약속할 자리치고는 꽤나 초라한 꼴이구나.","JPN":"伴侶同士で生涯を誓う場にしては、ずいぶんとみすぼらしい環境じゃな。","ENG":"This is not the place that I had in mind for my lavish celebration of eternal love.","TWN":"以一個伴侶互許終身的地點來說，這裡還真是有點寒酸呢！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"역시 눈앞에 나라는 답이 뻔히 있는데도 누굴 정실로 받아들일지 갈팡질팡하던 녀석다워.","JPN":"目の前に妾という明らかな答えがおるのに、誰を本妻として迎え入れるか迷っていた奴らしいのう。","ENG":"I should have known. You, even though the answer had been right in front of you, still couldn't decide whom you wanted as your lawful wife.","TWN":"你這傢伙看起來就是，就算眼前已經有一個像我這麼明確的答案，還是要考慮到底要娶誰才好！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"뭐, 됐다. 필멸자들이 말하는 부부란 서로 부족한 부분을 채워 줄 때 의미가 있다지.","JPN":"まあ、よかろう。定命の者が言う夫婦というものは、互いに足りぬ部分を補い合う意味があるそうじゃな。","ENG":"Oh, whatever. As you mortals say, couples should accept for each other's faults.","TWN":"算了，就像必滅者們說的，所謂的夫妻就是要彼此互補。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"그런데 잠깐, 나한테 부족한 부분이 있었나?","JPN":"いや、そもそも妾に足りぬところなどあったか？","ENG":"But wait, I'm faultless.","TWN":"等等！我有什麼不足的地方嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"빼어난 미모, 강력한 힘, 번뜩이는 지성과 날카로운 통찰력까지.","JPN":"人間離れした優れた美貌、強力な力、きらめく知性や鋭い洞察力。","ENG":"I'm beautiful, powerful, intelligent, and even insightful.","TWN":"出眾的外表、強大的力量、聰明的頭腦，再加上敏銳的觀察力！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"시종 녀석은 무슨 일이 있어도 도장부터 찍으라고 호들갑을 떨어댔다만…….","JPN":"僕のやつは何があろうと婚姻届に判を捺せと騒いでおったが……","ENG":"My servants told me to sign first and think later, but...","TWN":"侍從們一定會在旁邊悄悄說，不管怎麼樣印章先蓋下去再說啦……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"이렇게 완벽한 신부를 맞이하게 됐는데 너도 각오 한마디 정도는 해야지.","JPN":"ここまで完璧な花嫁を迎えることになるのなら、其方も覚悟の一言ぐらいはあるのじゃろう？","ENG":"You're marrying to such a flawless bride. What can you do for her?","TWN":"能娶到這麼完美的老婆，你也好歹說點什麼吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"시끄러! 네가 목말을 왜 태워 줘!","JPN":"ええい！　なぜ其方に肩車されなければならぬのじゃ！？","ENG":"Shut up! I don't want a ride on your shoulders!","TWN":"閉嘴！我為什麼要騎到你頭上！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"…라고, 화낼 줄 알았다면 큰 착각이다. 필멸자.","JPN":"……と、怒ると思ったなら大間違いだぞ、定命の者よ。","ENG":"... was what you expected? Then you're mistaken, mortal.","TWN":"…你以為我會發火這麼說嗎？那你可就大錯特錯囉！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"볼품은 없더라도, 다른 경쟁자들이 네 어깨에 기대는 꼴을 보는 것보단 내가 올라타는 게 마음 편하지.","JPN":"品位に欠けるとはいえ、他のライバルたちが其方の肩に寄りかかる様を見るよりは、妾が乗る方が気楽じゃ。","ENG":"I don't care if it's unsightly. I'd rather ride on your shoulders than let my competitors lean against them.","TWN":"雖然長得不怎麼起眼，但與其看到其他競爭者靠在你的肩膀上，我寧願是我騎在你頭上！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"자랑스럽게 여겨라. 내 것이 된다는 영광에 비견할 만한 업적 따위 이 세상에 존재하지 않거든.","JPN":"誇りに思うがよい。妾のものになれるという光栄に比肩することなど、この世に存在しないのじゃ。","ENG":"Be proud of yourself. You're becoming mine, and nothing else you do can beat that.","TWN":"這可是你的榮幸！這世界上沒有什麼事，是比成為我的東西還要榮耀的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"자, 알아들었으면 이리 가까이 와서 몸을 숙이도록.","JPN":"さあ、わかったならちこう寄れ。近くに来て跪くのじゃ。","ENG":"Now, if that's understood, come closer and lower your head.","TWN":"好了，聽懂的話，就靠近點彎下身來！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_WEDDING_NULL","text":{"KOREA":"맹세의 입맞춤을 허락해 줄 테니.","JPN":"誓いの口づけを許すとしよう。","ENG":"I'll let you kiss your bride.","TWN":"我就允許你可以對我進行誓約之吻！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};